import { useEffect, useMemo, useRef } from "react"
import { format, isValid, parseISO, startOfDay, subDays } from "date-fns"
import type {
  SemaphorInputHandle,
  SemaphorScalar,
} from "react-semaphor/data-app-sdk"

import {
  DateRangePicker,
  getPresetDateRange,
  getDateRangeLabel,
  type DateRange,
  type DateRangeDefaultPresetKey,
} from "./date-range-picker"

export type SemaphorDateRangeFilterProps = {
  label?: string
  handle: SemaphorInputHandle
  today?: Date
  align?: "start" | "end" | "center"
  fallbackDays?: number
  emptyLabel?: string
  defaultValue?: DateRange
  defaultPreset?: DateRangeDefaultPresetKey
  initializeWhenEmpty?: boolean
}

export function SemaphorDateRangeFilter({
  label,
  handle,
  today = startOfDay(new Date()),
  align = "start",
  fallbackDays = 30,
  emptyLabel = "Any time",
  defaultValue,
  defaultPreset,
  initializeWhenEmpty = false,
}: SemaphorDateRangeFilterProps) {
  const activeValue = toActiveDateRange(handle.value)
  const appliedDefaultKeyRef = useRef<string | null>(null)
  const explicitDefaultValue = useMemo(() => {
    if (defaultValue) return defaultValue
    if (defaultPreset) return getPresetDateRange(defaultPreset, today)
    if (initializeWhenEmpty) return fallbackDateRange(today, fallbackDays)
    return undefined
  }, [defaultPreset, defaultValue, fallbackDays, initializeWhenEmpty, today])
  const value =
    activeValue ??
    explicitDefaultValue ??
    fallbackDateRange(today, fallbackDays)

  useEffect(() => {
    if (!explicitDefaultValue || hasDateRangeValue(handle.value)) {
      return
    }
    const defaultKey = [
      formatDateValue(explicitDefaultValue.from),
      formatDateValue(explicitDefaultValue.to),
    ].join(":")
    if (appliedDefaultKeyRef.current === defaultKey) {
      return
    }
    appliedDefaultKeyRef.current = defaultKey
    handle.setValue([
      formatDateValue(explicitDefaultValue.from),
      formatDateValue(explicitDefaultValue.to),
    ])
  }, [explicitDefaultValue, handle])

  return (
    <DateRangePicker
      label={label ?? handle.label ?? "Date range"}
      value={value}
      today={today}
      align={align}
      emptyLabel={emptyLabel}
      isValueActive={Boolean(activeValue ?? explicitDefaultValue)}
      onChange={(next) => {
        handle.setValue([formatDateValue(next.from), formatDateValue(next.to)])
      }}
    />
  )
}

function hasDateRangeValue(value: SemaphorInputHandle["value"]) {
  return (
    Array.isArray(value) &&
    Boolean(parseDateValue(value[0]) && parseDateValue(value[1]))
  )
}

export function getSemaphorDateRangeFilterLabel(
  handle: SemaphorInputHandle,
  today = startOfDay(new Date()),
  fallbackDays = 30
) {
  const activeValue = toActiveDateRange(handle.value)
  if (!activeValue) return "Any time"
  return getDateRangeLabel(
    activeValue ?? fallbackDateRange(today, fallbackDays),
    today
  )
}

function toActiveDateRange(
  value: SemaphorInputHandle["value"]
): DateRange | null {
  const values = Array.isArray(value) ? value : []
  const from = parseDateValue(values[0])
  const to = parseDateValue(values[1])

  if (from && to) {
    return { from, to }
  }

  if (from) {
    return { from, to: from }
  }

  return null
}

function fallbackDateRange(today: Date, fallbackDays: number): DateRange {
  return {
    from: subDays(today, Math.max(1, fallbackDays) - 1),
    to: today,
  }
}

function parseDateValue(value: SemaphorScalar | undefined): Date | null {
  if (typeof value === "string" || typeof value === "number") {
    const date = typeof value === "number" ? new Date(value) : parseISO(value)
    return isValid(date) ? startOfDay(date) : null
  }

  return null
}

function formatDateValue(date: Date) {
  return format(date, "yyyy-MM-dd")
}

/* eslint-disable react-refresh/only-export-components */
import { useState } from "react"
import {
  startOfMonth,
  startOfYear,
  subDays,
  subMonths,
  startOfDay,
  format,
  isSameDay,
} from "date-fns"
import { CalendarIcon, ChevronDownIcon } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Calendar } from "@/components/ui/calendar"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"

export type DateRange = { from: Date; to: Date }

export type DateRangePresetKey =
  | "last_7_days"
  | "last_30_days"
  | "last_90_days"
  | "last_12_months"
  | "month_to_date"
  | "year_to_date"
  | "custom"

export type DateRangeDefaultPresetKey = Exclude<DateRangePresetKey, "custom">

type Preset = {
  key: DateRangeDefaultPresetKey
  label: string
  compute: (today: Date) => DateRange
}

const PRESETS: Preset[] = [
  {
    key: "last_7_days",
    label: "Last 7 days",
    compute: (today) => ({ from: subDays(today, 6), to: today }),
  },
  {
    key: "last_30_days",
    label: "Last 30 days",
    compute: (today) => ({ from: subDays(today, 29), to: today }),
  },
  {
    key: "last_90_days",
    label: "Last 90 days",
    compute: (today) => ({ from: subDays(today, 89), to: today }),
  },
  {
    key: "last_12_months",
    label: "Last 12 months",
    compute: (today) => ({ from: subMonths(today, 12), to: today }),
  },
  {
    key: "month_to_date",
    label: "Month to date",
    compute: (today) => ({ from: startOfMonth(today), to: today }),
  },
  {
    key: "year_to_date",
    label: "Year to date",
    compute: (today) => ({ from: startOfYear(today), to: today }),
  },
]

export type DateRangePickerProps = {
  value: DateRange
  onChange: (next: DateRange, preset: DateRangePresetKey) => void
  /** "Today" anchor used for preset math. Defaults to today. */
  today?: Date
  /** Optional explicit label. When omitted, the active preset/range is shown. */
  label?: string
  /** Text shown when the owning Semaphor input has no active date value. */
  emptyLabel?: string
  isValueActive?: boolean
  align?: "start" | "end" | "center"
}

export function DateRangePicker({
  value,
  onChange,
  today = startOfDay(new Date()),
  label = "Date range",
  emptyLabel = "Any time",
  isValueActive = true,
  align = "start",
}: DateRangePickerProps) {
  const [open, setOpen] = useState(false)
  const [draft, setDraft] = useState<DateRange>(value)
  const [activePreset, setActivePreset] = useState<DateRangePresetKey>(() =>
    detectPreset(value, today)
  )

  function handleOpenChange(nextOpen: boolean) {
    if (nextOpen) {
      setDraft(value)
      setActivePreset(detectPreset(value, today))
    }
    setOpen(nextOpen)
  }

  function selectPreset(preset: Preset) {
    const range = preset.compute(today)
    setDraft(range)
    setActivePreset(preset.key)
  }

  function selectCustom(range: { from?: Date; to?: Date } | undefined) {
    if (!range?.from) return
    setDraft({ from: range.from, to: range.to ?? range.from })
    setActivePreset("custom")
  }

  function apply() {
    onChange(draft, activePreset)
    setOpen(false)
  }

  const triggerValue = isValueActive
    ? formatTriggerValue(value, detectPreset(value, today))
    : emptyLabel

  return (
    <Popover open={open} onOpenChange={handleOpenChange}>
      <PopoverTrigger
        render={
          <button
            type="button"
            className="inline-flex h-8 items-center gap-2 rounded-md border bg-card px-2.5 text-xs transition-colors hover:bg-secondary"
          />
        }
      >
        <CalendarIcon className="size-3.5" />
        <span className="text-muted-foreground">{label}</span>
        <span className="font-medium text-foreground">{triggerValue}</span>
        <ChevronDownIcon className="size-3.5 text-muted-foreground" />
      </PopoverTrigger>

      <PopoverContent align={align} className="w-auto p-0">
        <div className="flex flex-col md:flex-row">
          <ul className="flex w-full shrink-0 flex-col gap-0.5 border-b p-2 md:w-40 md:border-r md:border-b-0">
            {PRESETS.map((preset) => {
              const isActive = activePreset === preset.key
              return (
                <li key={preset.key}>
                  <button
                    type="button"
                    onClick={() => selectPreset(preset)}
                    className={cn(
                      "w-full rounded-md px-2.5 py-1.5 text-left text-xs transition-colors",
                      isActive
                        ? "bg-secondary text-foreground"
                        : "text-muted-foreground hover:bg-secondary/60 hover:text-foreground"
                    )}
                  >
                    {preset.label}
                  </button>
                </li>
              )
            })}
            <li className="mt-0.5 border-t pt-1.5">
              <span
                className={cn(
                  "block px-2.5 py-1.5 text-xs",
                  activePreset === "custom"
                    ? "font-medium text-foreground"
                    : "text-muted-foreground"
                )}
              >
                Custom range
              </span>
            </li>
          </ul>
          <div className="p-2">
            <Calendar
              mode="range"
              numberOfMonths={2}
              selected={draft}
              onSelect={selectCustom}
              defaultMonth={draft.from}
              required
            />
            <div className="flex items-center justify-between gap-3 border-t px-1 pt-3 text-xs">
              <span className="text-muted-foreground tabular-nums">
                {formatRange(draft)}
              </span>
              <div className="flex gap-2">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setOpen(false)}
                >
                  Cancel
                </Button>
                <Button size="sm" onClick={apply}>
                  Apply
                </Button>
              </div>
            </div>
          </div>
        </div>
      </PopoverContent>
    </Popover>
  )
}

/**
 * Returns the user-facing label for a date range - either the preset name
 * (e.g., "Last 30 days") or a formatted range when the dates don't match any
 * preset.
 */
export function getDateRangeLabel(range: DateRange, today: Date): string {
  return formatTriggerValue(range, detectPreset(range, today))
}

export function getPresetDateRange(
  presetKey: DateRangeDefaultPresetKey,
  today: Date
): DateRange | undefined {
  return PRESETS.find((preset) => preset.key === presetKey)?.compute(today)
}

function detectPreset(range: DateRange, today: Date): DateRangePresetKey {
  for (const preset of PRESETS) {
    const candidate = preset.compute(today)
    if (
      isSameDay(candidate.from, range.from) &&
      isSameDay(candidate.to, range.to)
    ) {
      return preset.key
    }
  }
  return "custom"
}

function formatTriggerValue(
  range: DateRange,
  preset: DateRangePresetKey
): string {
  if (preset === "custom") return formatRange(range)
  return PRESETS.find((p) => p.key === preset)?.label ?? formatRange(range)
}

function formatRange(range: DateRange): string {
  const sameYear = range.from.getFullYear() === range.to.getFullYear()
  const fromStr = format(range.from, sameYear ? "MMM d" : "MMM d, yyyy")
  const toStr = format(range.to, "MMM d, yyyy")
  return `${fromStr} - ${toStr}`
}

import type {
  SemaphorInputHandle,
  SemaphorInputOption,
} from "react-semaphor/data-app-sdk"

import {
  MultiSelectFilter,
  type MultiSelectFilterProps,
} from "./multi-select-filter"
import {
  SingleSelectFilter,
  type SingleSelectFilterProps,
} from "./single-select-filter"
import {
  createSemaphorOptionAdapter,
  isSemaphorOptionValue,
  semaphorOptionValueKey,
  toOptionValueArray,
  toSingleOptionValue,
} from "./option-adapter"

type CommonSemaphorFilterProps = {
  label: string
  handle: SemaphorInputHandle
  options?: SemaphorInputOption[]
}

export type SemaphorMultiSelectFilterProps = CommonSemaphorFilterProps &
  Pick<MultiSelectFilterProps, "emptyLabel" | "searchPlaceholder" | "align">

export type SemaphorSingleSelectFilterProps = CommonSemaphorFilterProps &
  Pick<
    SingleSelectFilterProps,
    "emptyLabel" | "searchPlaceholder" | "allowClear" | "hideSearch" | "align"
  >

export function SemaphorMultiSelectFilter({
  label,
  handle,
  options,
  ...filterProps
}: SemaphorMultiSelectFilterProps) {
  const adapter = createSemaphorOptionAdapter(options ?? handle.options)
  const selectedValues = toOptionValueArray(handle.value)

  return (
    <MultiSelectFilter
      label={label}
      options={adapter.uiOptions}
      value={selectedValues.map(semaphorOptionValueKey)}
      onChange={(nextKeys) => {
        const nextValues = nextKeys
          .map((key) => adapter.rawValueByKey.get(key))
          .filter(isSemaphorOptionValue)
        handle.setValue(nextValues.length > 0 ? nextValues : undefined)
      }}
      {...filterProps}
    />
  )
}

export function SemaphorSingleSelectFilter({
  label,
  handle,
  options,
  ...filterProps
}: SemaphorSingleSelectFilterProps) {
  const adapter = createSemaphorOptionAdapter(options ?? handle.options)
  const selectedValue = toSingleOptionValue(handle.value)

  return (
    <SingleSelectFilter
      label={label}
      options={adapter.uiOptions}
      value={
        selectedValue === undefined
          ? null
          : semaphorOptionValueKey(selectedValue)
      }
      onChange={(nextKey) => {
        if (!nextKey) {
          handle.setValue(undefined)
          return
        }
        handle.setValue(adapter.rawValueByKey.get(nextKey))
      }}
      {...filterProps}
    />
  )
}

import { useState } from "react"
import { CheckIcon, ChevronDownIcon } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"

export type FilterOption = {
  label: string
  value: string
}

export type MultiSelectFilterProps = {
  label: string
  options: FilterOption[]
  value: string[]
  onChange: (next: string[]) => void
  /** Label shown when no options are selected. Defaults to "All". */
  emptyLabel?: string
  /** Search placeholder. */
  searchPlaceholder?: string
  align?: "start" | "end" | "center"
}

export function MultiSelectFilter({
  label,
  options,
  value,
  onChange,
  emptyLabel = "All",
  searchPlaceholder,
  align = "start",
}: MultiSelectFilterProps) {
  const [open, setOpen] = useState(false)
  const triggerValue = formatTriggerValue(value, options, emptyLabel)

  function toggle(optionValue: string) {
    if (value.includes(optionValue)) {
      onChange(value.filter((v) => v !== optionValue))
    } else {
      onChange([...value, optionValue])
    }
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger
        render={
          <button
            type="button"
            className="inline-flex h-8 items-center gap-2 rounded-md border bg-card px-2.5 text-xs transition-colors hover:bg-secondary"
          />
        }
      >
        <span className="text-muted-foreground">{label}</span>
        <span className="font-medium text-foreground">{triggerValue}</span>
        <ChevronDownIcon className="size-3.5 text-muted-foreground" />
      </PopoverTrigger>

      <PopoverContent
        align={align}
        className="w-64 p-0"
      >
        <Command>
          <CommandInput placeholder={searchPlaceholder ?? `Search ${label.toLowerCase()}...`} />
          <CommandList>
            <CommandEmpty>No results found.</CommandEmpty>
            <CommandGroup>
              {options.map((option) => {
                const selected = value.includes(option.value)
                return (
                  <CommandItem
                    key={option.value}
                    value={option.label}
                    onSelect={() => toggle(option.value)}
                    className="flex items-center gap-2"
                  >
                    <div
                      className={cn(
                        "flex size-4 shrink-0 items-center justify-center rounded-sm border",
                        selected
                          ? "border-primary bg-primary text-primary-foreground"
                          : "border-border bg-card",
                      )}
                    >
                      {selected ? <CheckIcon className="size-3" /> : null}
                    </div>
                    <span className="flex-1 truncate">{option.label}</span>
                  </CommandItem>
                )
              })}
            </CommandGroup>
          </CommandList>
        </Command>
        <div className="flex items-center justify-between gap-2 border-t px-2 py-2 text-[11px] text-muted-foreground">
          {value.length > 0 ? (
            <Button
              size="sm"
              variant="ghost"
              className="h-6 px-2 text-xs"
              onClick={() => onChange([])}
            >
              Clear
            </Button>
          ) : (
            <span />
          )}
          <span className="tabular-nums">
            {value.length === 0
              ? `${options.length} options`
              : `${value.length} of ${options.length} selected`}
          </span>
          <Button
            size="sm"
            variant="ghost"
            className="h-6 px-2 text-xs"
            onClick={() => setOpen(false)}
          >
            Done
          </Button>
        </div>
      </PopoverContent>
    </Popover>
  )
}

function formatTriggerValue(
  selected: string[],
  options: FilterOption[],
  emptyLabel: string,
): string {
  if (selected.length === 0) return emptyLabel
  if (selected.length === 1) {
    const found = options.find((o) => o.value === selected[0])
    return found?.label ?? selected[0]
  }
  return `${selected.length} selected`
}

import type {
  SemaphorInputOption,
  SemaphorInputValue,
  SemaphorOptionValue,
} from "react-semaphor/data-app-sdk"

export function createSemaphorOptionAdapter(options: SemaphorInputOption[]) {
  const rawValueByKey = new Map<string, SemaphorOptionValue>()
  const uiOptions = options.map((option) => {
    const value = semaphorOptionValueKey(option.value)
    rawValueByKey.set(value, option.value)
    return {
      label: option.label,
      value,
    }
  })

  return { uiOptions, rawValueByKey }
}

export function semaphorOptionValueKey(value: SemaphorOptionValue): string {
  return `${typeof value}:${String(value)}`
}

export function toOptionValueArray(value: SemaphorInputValue | undefined) {
  if (Array.isArray(value)) {
    return value.filter(isSemaphorOptionValue)
  }
  return isSemaphorOptionValue(value) ? [value] : []
}

export function toSingleOptionValue(
  value: SemaphorInputValue | undefined
): SemaphorOptionValue | undefined {
  if (Array.isArray(value)) {
    return value.find(isSemaphorOptionValue)
  }
  return isSemaphorOptionValue(value) ? value : undefined
}

export function isSemaphorOptionValue(
  value: SemaphorInputValue | undefined
): value is SemaphorOptionValue {
  return (
    typeof value === "string" ||
    typeof value === "number" ||
    typeof value === "boolean"
  )
}

import { useState } from "react"
import { CheckIcon, ChevronDownIcon } from "lucide-react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import type { FilterOption } from "./multi-select-filter"

export type SingleSelectFilterProps = {
  label: string
  options: FilterOption[]
  value: string | null
  onChange: (next: string | null) => void
  /** Label shown when nothing is selected. Defaults to "All". */
  emptyLabel?: string
  searchPlaceholder?: string
  allowClear?: boolean
  /** Hide the search input for short, scannable option lists. */
  hideSearch?: boolean
  align?: "start" | "end" | "center"
}

export function SingleSelectFilter({
  label,
  options,
  value,
  onChange,
  emptyLabel = "All",
  searchPlaceholder,
  allowClear = true,
  hideSearch = false,
  align = "start",
}: SingleSelectFilterProps) {
  const [open, setOpen] = useState(false)
  const selected = options.find((o) => o.value === value)
  const triggerValue = selected?.label ?? emptyLabel

  function selectValue(next: string) {
    onChange(next)
    setOpen(false)
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger
        render={
          <button
            type="button"
            className="inline-flex h-8 items-center gap-2 rounded-md border bg-card px-2.5 text-xs transition-colors hover:bg-secondary"
          />
        }
      >
        <span className="text-muted-foreground">{label}</span>
        <span className="font-medium text-foreground">{triggerValue}</span>
        <ChevronDownIcon className="size-3.5 text-muted-foreground" />
      </PopoverTrigger>

      <PopoverContent align={align} className="w-56 p-0">
        <Command>
          {!hideSearch ? (
            <CommandInput
              placeholder={
                searchPlaceholder ?? `Search ${label.toLowerCase()}...`
              }
            />
          ) : null}
          <CommandList>
            <CommandEmpty>No results found.</CommandEmpty>
            <CommandGroup>
              {options.map((option) => {
                const isSelected = option.value === value
                return (
                  <CommandItem
                    key={option.value}
                    value={option.label}
                    onSelect={() => selectValue(option.value)}
                    className="flex items-center gap-2"
                  >
                    <CheckIcon
                      className={cn(
                        "size-3.5",
                        isSelected
                          ? "text-foreground"
                          : "text-transparent",
                      )}
                    />
                    <span className="flex-1 truncate">{option.label}</span>
                  </CommandItem>
                )
              })}
            </CommandGroup>
          </CommandList>
        </Command>
        {allowClear && value ? (
          <div className="flex items-center justify-end border-t px-2 py-2">
            <Button
              size="sm"
              variant="ghost"
              className="h-6 px-2 text-xs text-muted-foreground"
              onClick={() => {
                onChange(null)
                setOpen(false)
              }}
            >
              Clear
            </Button>
          </div>
        ) : null}
      </PopoverContent>
    </Popover>
  )
}
